const analysis = item?.candidates?.[0]?.content?.parts?.[0]?.text || "";

if (!analysis) {
  throw new Error("Empty Gemini response. Keys: " + JSON.stringify(Object.keys(item)));
}

const prevNode = $('Code in JavaScript').first().json;

return [{
