    fileSize: prevNode.fileSize || 0,
    mergedContext: ("PRODUCT NAME: " + prevNode.productName + "\n\n=== GEMINI COMPLETE VIDEO ANALYSIS ===\n" + analysis).substring(0, 8000)
  }
}];

