const item = $input.first().json;
const parts = item?.candidates?.[0]?.content?.parts || [];

// Find the image part
const imagePart = parts.find(p => p.inlineData);
const textPart = parts.find(p => p.text);

if (!imagePart) {
  throw new Error("No image found. Parts: " + JSON.stringify(parts.map(p => Object.keys(p))));
}

return [{
  json: {
    ...$('Code in JavaScript7').first().json,
    imageBase64: imagePart.inlineData.data,
    imageMimeType: imagePart.inlineData.mimeType || "image/png",
    imageDescription: textPart?.text || ""
  }
}];

const item = $input.first().json;

// Check if operation is complete
if (!item.done) {
  throw new Error("Video not ready yet. State: " + JSON.stringify(item));
}

const videoUri = item?.response?.generateVideoResponse?.generatedSamples?.[0]?.video?.uri || 
                 item?.response?.videos?.[0]?.uri || "";

if (!videoUri) {
  throw new Error("No video URI. Response: " + JSON.stringify(item));
}

return [{
  json: {
    ...$('Code in JavaScript7').first().json,
    videoUri: videoUri
  }
}];

