const item = $input.first().json;

// Parse storyboard text into scenes
const storyboard = item.storyboard || "";
const screenplay = item.screenplay || "";

// Extract scenes using regex - matches "Scene X:" pattern
const sceneRegex = /\*\*Scene\s*(\d+)[^*]*\*\*\s*([\s\S]*?)(?=\*\*Scene\s*\d+|\*\*END|$)/gi;

const scenes = [];
let match;

while ((match = sceneRegex.exec(storyboard)) !== null) {
  const sceneText = match[2];

  // Extract fields from each scene block
  const get = (label) => {
    const r = new RegExp(`${label}[:\\s]+([^\\n*]+)`, 'i');
    const m = sceneText.match(r);
    return m ? m[1].trim() : "";
  };

  const duration = parseInt(get("duration")) || 8;
  const visualDesc = get("Visual description");
  const cameraShot = get("Camera shot type");
  const cameraMove = get("Camera movement");
  const voiceover = get("Audio/VO line");
  const transition = get("Transition");
  const bgMusic = get("Background music");

  // Build Veo-optimized prompt
  const videoPrompt = `${visualDesc}. ${cameraShot}, ${cameraMove}. ${bgMusic ? 'Background: ' + bgMusic : ''}. Cinematic, 4K, professional quality. ${transition ? 'End with: ' + transition : ''}`.trim();

  scenes.push({
    sceneNumber: parseInt(match[1]),
    duration: Math.min(Math.max(duration, 4), 8), // clamp between 4-8
    videoPrompt,
    voiceover,
    visualDesc,
    productName: item.productName
  });
}

// Fallback if regex finds nothing
if (scenes.length === 0) {
  throw new Error(`No scenes parsed. Storyboard preview: ${storyboard.substring(0, 200)}`);
}

console.log(`Parsed ${scenes.length} scenes`);
return scenes.map(s => ({ json: s }));

const item = $input.first().json;

// Extract video URI from completed operation
const videoUri = item?.response?.generateVideoResponse
  ?.generatedSamples?.[0]?.video?.uri;

if (!videoUri) {
  throw new Error("No video URI found: " + JSON.stringify(item));
}

return [{
  json: {
    videoUri,
    sceneNumber: item.sceneNumber || 0,
    videoPrompt: item.videoPrompt || "",
    voiceover: item.voiceover || "",
    duration: item.duration || 8
  }
}];

const clips = $input.all();

// Sort by scene number
clips.sort((a, b) => a.json.sceneNumber - b.json.sceneNumber);

let start = 0;
const videoClips = clips.map(clip => {
  const length = clip.json.duration || 8;
  const c = {
    asset: { type: "video", src: clip.json.publicUrl },
    start,
    length,
    transition: { in: "fade", out: "fade" }
  };
  start += length;
  return c;
});

// Build voiceover track
const voClips = clips.map((clip, i) => ({
  asset: {
    type: "audio",
    src: clip.json.voiceoverUrl || ""
  },
  start: i * 8,
  length: clip.json.duration || 8
}));

return [{
  json: {
    totalDuration: start,
    shotstackPayload: {
      timeline: {
        tracks: [
          { clips: videoClips },
          ...(clips[0].json.voiceoverUrl ? [{ clips: voClips }] : [])
        ]
      },
      output: {
        format: "mp4",
        resolution: "hd",
        fps: 25
      }
    }
  }
}];

const item = $input.first().json;

const finalUrl = item?.response?.url;
const status = item?.response?.status;

if (status === 'failed') {
  throw new Error("Shotstack render failed: " + JSON.stringify(item));
}

if (!finalUrl) {
  throw new Error("No URL found in response: " + JSON.stringify(item));
}

return [{
  json: {
    finalVideoUrl: finalUrl,
    renderId: item.response.id,
    duration: item.response.data?.output?.duration || 0
  }
}];

